const villes = [
  { nom: 'VILLE_1', lat: LATITUDE_1, lon: LONGITUDE_1 },
  { nom: 'VILLE_2', lat: LATITUDE_2, lon: LONGITUDE_2 },
  { nom: 'VILLE_3', lat: LATITUDE_3, lon: LONGITUDE_3 }
];

return villes.map(v => ({ json: v }));

const items = $input.all();
const villes = $('VILLES').all();
const messages = items.map((item, index) => {
  const ville = villes[index]?.json?.nom || 'Ville inconnue';
  const daily = item.json.daily;
  const tempMax = daily.temperature_2m_max[0];
  const tempMin = daily.temperature_2m_min[0];
  const pluie = daily.precipitation_sum[0];
  const vent = daily.windspeed_10m_max[0];
  const code = daily.weathercode[0];
  let meteo = '🌤️ Variable';
  if (code === 0) meteo = '☀️ Ensoleillé';
  else if (code <= 3) meteo = '🌤️ Peu nuageux';
  else if (code <= 48) meteo = '☁️ Nuageux/Brouillard';
  else if (code <= 67) meteo = '🌧️ Pluie';
  else if (code <= 77) meteo = '❄️ Neige';
  else if (code <= 82) meteo = '🌦️ Averses';
  else meteo = '⛈️ Orage';
  let conseil = '✅ Bonnes conditions pour rouler !';
  if (pluie > 5) conseil = '❌ Pluie trop importante, évite de sortir.';
  else if (pluie > 0) conseil = '⚠️ Légère pluie prévue, sois prudent.';
  else if (vent > 60) conseil = '⚠️ Vent fort, attention en moto !';
  else if (tempMax < 5) conseil = '⚠️ Températures basses, route potentiellement glissante.';
  return `📍 **${ville}**\n${meteo}\n🌡️ ${tempMin}°C → ${tempMax}°C\n💨 Vent : ${vent} km/h\n🌧️ Pluie : ${pluie} mm\n${conseil}`;
});
const heure = new Date().getHours();
const titre = heure < 12
  ? `🏍️ **Météo Moto du ${new Date().toLocaleDateString('fr-FR')}**`
  : `🏍️ **Météo Moto demain ${new Date(Date.now() + 86400000).toLocaleDateString('fr-FR')}**`;
const content = `${titre}\n\n${messages.join('\n\n---\n\n')}`.substring(0, 1990);
return [{ json: { content } }];
